const d = $input.first().json.dashboard;
const byPhase = d.projects.by_phase || {};
const phaseRows = Object.entries(byPhase).map(([k,v]) => '<tr><td style=\"padding:4px 10px\">' + k + '</td><td style=\"padding:4px 10px;text-align:right\"><b>' + v + '</b></td></tr>').join('');
const kpi = (label, val, danger) => '<tr><td style=\"padding:6px 12px\">' + label + '</td><td style=\"padding:6px 12px;text-align:right\"' + (danger ? ' bgcolor=\"#ffe0e0\"' : '') + '><b>' + (val !== null && val !== undefined ? val : '-') + '</b></td></tr>';
const html = `<div style=\"font-family:Arial,sans-serif;max-width:720px;margin:0 auto\">
<h2 style=\"color:#2c3e50\">KPIs semanales — ArquitAI</h2>
<p style=\"color:#7f8c8d\">Resumen del estado del estudio. Generado: ${d.generated_at}</p>

<h3 style=\"color:#2c3e50\">Proyectos</h3>
<table style=\"border-collapse:collapse;width:100%\">
${kpi('Activos', d.projects.total_active)}
${kpi('Completados ult. 30d', d.projects.completed_last_30d)}
${kpi('Mas antiguo sin tocar (dias)', d.projects.oldest_active_days, d.projects.oldest_active_days > 30)}
</table>
<h4>Por fase</h4>
<table style=\"border-collapse:collapse\">${phaseRows}</table>

<h3 style=\"color:#2c3e50;margin-top:24px\">Contratos</h3>
<table style=\"border-collapse:collapse;width:100%\">
${kpi('Pendientes de firma', d.contracts.pending_signature, d.contracts.pending_signature > 3)}
${kpi('Expiran en 7d', d.contracts.expiring_7d, d.contracts.expiring_7d > 0)}
${kpi('Firmados ult. 30d', d.contracts.signed_last_30d)}
</table>

<h3 style=\"color:#2c3e50;margin-top:24px\">Colaboradores</h3>
<table style=\"border-collapse:collapse;width:100%\">
${kpi('Asignaciones activas', d.collaborators.active_assignments)}
${kpi('Overdue', d.collaborators.overdue, d.collaborators.overdue > 0)}
${kpi('Pendientes revision', d.collaborators.pending_review, d.collaborators.pending_review > 0)}
</table>

<h3 style=\"color:#2c3e50;margin-top:24px\">Postventa / Permisos / QC</h3>
<table style=\"border-collapse:collapse;width:100%\">
${kpi('Aftercare abierto', d.aftercare.open)}
${kpi('Aftercare urgente', d.aftercare.urgent_open, d.aftercare.urgent_open > 0)}
${kpi('Permisos en progreso', d.permits.in_progress)}
${kpi('QC checks abiertos', d.qc_checks.open)}
</table>

<h3 style=\"color:#2c3e50;margin-top:24px\">Pendientes de tu atencion</h3>
<table style=\"border-collapse:collapse;width:100%\">
${kpi('Anomalias sin revisar', d.anomalies.unreviewed, d.anomalies.unreviewed > 0)}
${kpi('Consultas pendientes', d.consultations.pending, d.consultations.pending > 0)}
${kpi('Facturas pendientes aprobar', d.finance.invoices_pending_approval, d.finance.invoices_pending_approval > 0)}
</table>

<h3 style=\"color:#2c3e50;margin-top:24px\">Finanzas</h3>
<table style=\"border-collapse:collapse;width:100%\">
${kpi('Facturas pagadas ult. 30d (EUR)', d.finance.invoices_paid_last_30d_total_eur)}
</table>

<h3 style=\"color:#2c3e50;margin-top:24px\">Salud sistema</h3>
<table style=\"border-collapse:collapse;width:100%\">
${kpi('Errores workflow ult. 24h', d.errors_last_24h, d.errors_last_24h > 5)}
</table>

<p style=\"font-size:11px;color:#95a5a6;margin-top:24px\">Endpoint API equivalente: <code>GET /webhook/dashboard-summary</code> con X-API-Key.</p>
</div>`;
const totalAlerts = (d.aftercare.urgent_open || 0) + (d.contracts.expiring_7d || 0) + (d.collaborators.overdue || 0) + (d.anomalies.unreviewed || 0);
return [{ json: { html_body: html, subject: 'ArquitAI — KPIs semanales' + (totalAlerts > 0 ? ' (' + totalAlerts + ' alertas)' : '') } }];

